INSERT INTO `settings` VALUES('97','terms_body_html','<p class=\"lead\">Last updated: February 11, 2026</p><h2>1. Acceptance of Terms</h2><p>By accessing and using RentSmart, you accept and agree to be bound by the terms and conditions of this agreement.</p><h2>2. Description of Service</h2><p>RentSmart provides property management software services including:</p><ul><li>Property and tenant management</li><li>Rent collection and payment processing</li><li>Financial reporting</li><li>Document management</li></ul><h2>3. User Accounts</h2><p>To use RentSmart, you must:</p><ul><li>Create an account with accurate information</li><li>Maintain the security of your account</li><li>Notify us of any unauthorized access</li><li>Be at least 18 years old</li></ul><h2>4. Subscription and Payments</h2><p>Our service is provided on a subscription basis:</p><ul><li>Subscription fees are billed monthly or annually</li><li>Payments are non-refundable</li><li>We may change pricing with 30 days notice</li><li>Free trial periods are available for new users</li></ul><h2>5. User Responsibilities</h2><p>You agree to:</p><ul><li>Comply with all applicable laws</li><li>Maintain accurate records</li><li>Protect tenant privacy</li><li>Use the service responsibly</li></ul><h2>6. Data Ownership</h2><p>You retain all rights to your data. We will:</p><ul><li>Protect your data security</li><li>Not access your data without permission</li><li>Delete your data upon account termination</li><li>Allow data export in standard formats</li></ul><h2>7. Service Availability</h2><p>While we strive for 99.9% uptime:</p><ul><li>We may perform scheduled maintenance</li><li>Service may be occasionally interrupted</li><li>We\'re not liable for downtime beyond our control</li></ul><h2>8. Termination</h2><p>We may terminate service if you:</p><ul><li>Violate these terms</li><li>Fail to pay subscription fees</li><li>Engage in fraudulent activity</li><li>Abuse the service</li></ul><h2>9. Contact Information</h2><p>For questions about these terms, contact us at:</p><ul><li>Email: rentsmart@timestentechnologies.co.ke</li><li>Phone: +254 795 155 230</li><li>Address: Nairobi, Kenya</li></ul>','2026-02-11 11:29:47','2026-02-11 12:00:56');
INSERT INTO `settings` VALUES('98','privacy_body_html','<p class=\"lead\">Last updated: February 11, 2026</p><h2>1. Information We Collect</h2><p>We collect information that you provide directly to us, including:</p><ul><li>Name and contact information</li><li>Property management details</li><li>Payment information</li><li>Communication preferences</li></ul><h2>2. How We Use Your Information</h2><p>We use the information we collect to:</p><ul><li>Provide and maintain our services</li><li>Process your transactions</li><li>Send you important updates</li><li>Improve our services</li><li>Comply with legal obligations</li></ul><h2>3. Information Sharing</h2><p>We do not sell your personal information. We may share your information with:</p><ul><li>Service providers who assist in our operations</li><li>Legal authorities when required by law</li><li>Business partners with your consent</li></ul><h2>4. Data Security</h2><p>We implement appropriate security measures to protect your personal information, including:</p><ul><li>Encryption of sensitive data</li><li>Regular security assessments</li><li>Access controls and authentication</li><li>Secure data storage</li></ul><h2>5. Your Rights</h2><p>You have the right to:</p><ul><li>Access your personal information</li><li>Correct inaccurate data</li><li>Request deletion of your data</li><li>Opt-out of marketing communications</li></ul><h2>6. Contact Us</h2><p>If you have any questions about this Privacy Policy, please contact us at:</p><ul><li>Email: rentsmart@timestentechnologies.co.ke</li><li>Phone: +254 795 155 230</li><li>Address: Nairobi, Kenya</li></ul>','2026-02-11 11:29:47','2026-02-11 12:00:56');
